const botaoAbrirBarraNavLateral=document.querySelector("#botao-abrir-barra-nav-lateral");const fundoBarraNavLateral=document.querySelector("#fundo-barra-nav-lateral");const barraNavLateral=document.querySelector("#barra-nav-lateral");const botaoFecharBarraNavLateral=document.querySelector("#botao-fechar-barra-nav-lateral");const fundoDialogo=document.querySelector("#fundo-dialogo");const dialogo=document.querySelector("#dialogo");const txtDialogo=document.querySelector("#txt-dialogo");const botaoFecharDialogo=document.querySelector("#botao-fechar-dialogo");const alternarBarraNavLateral=(exibir=!1)=>alternarVisibilidade([fundoBarraNavLateral,barraNavLateral],exibir);const alternarVisibilidade=(els,exibir)=>els.forEach((el)=>el.classList.toggle("esconder",!exibir));const alternarDialogo=(exibir=!1,msg="")=>{alternarVisibilidade([fundoDialogo,dialogo],exibir);if(exibir&&msg)txtDialogo.textContent=msg;else setTimeout(()=>(txtDialogo.textContent=msg),500)};const adicionarEventoAlternancia=(els,funcao)=>els.forEach((el)=>el.addEventListener("click",funcao));window.addEventListener("pageshow",()=>alternarBarraNavLateral());window.addEventListener("resize",(e)=>{if(e.currentTarget.innerWidth>=768)alternarBarraNavLateral();});document.addEventListener("keydown",(e)=>{if(e.key==="Escape"){alternarBarraNavLateral();alternarDialogo()}});botaoAbrirBarraNavLateral.addEventListener("click",()=>alternarBarraNavLateral(!0));adicionarEventoAlternancia([fundoBarraNavLateral,botaoFecharBarraNavLateral],()=>alternarBarraNavLateral());adicionarEventoAlternancia([fundoDialogo,botaoFecharDialogo],()=>alternarDialogo())